char *
proxsuite_c_module_print_version (proxsuite_c_context *ctx,
                                  const char *delimiter)
{
  proxsuite_c_context_begin_call(ctx);
  try {
    auto value{printVersion(std::string{delimiter == nullptr ? "" : delimiter})};
    auto* out{static_cast<char*>(std::malloc(value.size() + 1))};
    if (out == nullptr) return nullptr;
    std::memcpy(out, value.c_str(), value.size() + 1);
    return out;
  }
  catch (const std::bad_alloc& e) {
    proxsuite_c_context_set_error(ctx, PROXSUITE_C_BAD_ALLOC, e.what());
    return nullptr;
  }
  catch (const std::invalid_argument& e) {
    proxsuite_c_context_set_error(ctx, PROXSUITE_C_INVALID_ARG, e.what());
    return nullptr;
  }
  catch (const std::exception& e) {
    proxsuite_c_context_set_error(ctx, PROXSUITE_C_EXCEPTION, e.what());
    return nullptr;
  }
  catch (...) {
    proxsuite_c_context_set_error(ctx, PROXSUITE_C_UNKNOWN_ERROR, "unknown C++ exception");
    return nullptr;
  }
}
